<div class="catalog-actions" id="catalog-actions" hidden aria-hidden="true">
  <button class="catalog-dialog-backdrop" type="button" data-catalog-actions-close aria-label="إغلاق"></button>
  <section class="catalog-actions-panel" role="dialog" aria-modal="true" aria-labelledby="catalog-actions-title">
    <span class="catalog-actions-grip"></span><b id="catalog-actions-title">خيارات العنصر</b><small>اختر الإجراء المطلوب</small>
    <button class="catalog-action-edit" type="button" data-catalog-edit><svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 20h4L19 9l-4-4L4 16v4zM13 7l4 4"/></svg>تعديل</button>
    <form method="post" action="<?= e((string)($baseUrl ?? ('/' . ADMIN_PATH . '/channel-catalog'))) ?>" onsubmit="return confirm(<?= e(json_encode((string)$catalogDeleteText, JSON_UNESCAPED_UNICODE) ?: "''") ?>)">
      <input type="hidden" name="_csrf" value="<?= e($csrf) ?>"><input type="hidden" name="id" value="" data-catalog-delete-id>
      <button class="catalog-action-delete" type="submit" name="<?= e($catalogDeleteField) ?>"><svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 7h16M9 7V4h6v3M7 7l1 13h8l1-13"/></svg>حذف</button>
    </form>
    <button class="catalog-action-cancel" type="button" data-catalog-actions-close>إلغاء</button>
  </section>
</div>

<style>
.catalog-toolbar{display:flex;align-items:center;justify-content:space-between;gap:16px;margin-bottom:18px;padding:18px 20px;border:1px solid var(--line);border-radius:18px;background:linear-gradient(135deg,rgba(76, 14, 205,.1),rgba(124, 77, 255,.05))}.catalog-toolbar b{display:block;font-size:20px}.catalog-toolbar small{display:block;color:var(--tx2);margin-top:2px}.catalog-toolbar .btn{margin:0;flex:none}.catalog-parent-label{display:inline-flex;color:var(--p2);font-weight:800;font-size:12px;margin-bottom:2px}.catalog-back{display:inline-flex;color:var(--tx2);font-weight:800;margin-bottom:12px}.catalog-admin-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px}.catalog-admin-card{position:relative;display:flex;align-items:center;gap:13px;width:100%;min-height:92px;padding:14px;text-align:start;color:var(--tx);font:inherit;background:rgba(27, 7, 97,.82);border:1px solid var(--line);border-radius:16px;box-shadow:0 9px 26px rgba(0,0,0,.2);cursor:pointer;touch-action:pan-y;-webkit-tap-highlight-color:transparent;-webkit-touch-callout:none;-webkit-user-select:none;user-select:none;transition:.18s}.catalog-admin-card img{-webkit-user-drag:none}.catalog-admin-card:hover{border-color:rgba(124, 77, 255,.32);transform:translateY(-1px)}.catalog-admin-card:active,.catalog-admin-card.is-holding{transform:scale(.98);border-color:var(--p)}.catalog-admin-card.is-hidden{opacity:.55}.catalog-card-icon{width:52px;height:52px;display:grid;place-items:center;flex:none;border-radius:14px;color:var(--p2);background:rgba(124, 77, 255,.1)}.catalog-card-image{width:84px;height:64px;display:grid;place-items:center;flex:none;border-radius:13px;overflow:hidden;background:#080f1d}.catalog-card-image img{width:100%;height:100%;object-fit:contain}.catalog-card-copy{display:block;min-width:0;flex:1}.catalog-card-copy b,.catalog-card-copy small,.catalog-card-copy em{display:block}.catalog-card-copy b{font-size:15px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.catalog-card-copy small{color:var(--tx2);font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.catalog-card-copy em{font-style:normal;color:var(--p);font-size:11px;margin-top:4px}.catalog-card-arrow{flex:none;color:var(--tx3)}.catalog-hold-hint{position:absolute;inset-inline-end:12px;bottom:8px;color:var(--tx3);font-size:9px}.catalog-empty{text-align:center;padding:36px 20px}.catalog-empty p{color:var(--tx2)}.catalog-dialog,.catalog-actions{position:fixed;inset:0;z-index:100;display:grid;place-items:center;padding:18px}.catalog-dialog[hidden],.catalog-actions[hidden]{display:none}.catalog-dialog-backdrop{position:absolute;inset:0;width:100%;height:100%;border:0;background:rgba(10, 2, 38,.76);-webkit-backdrop-filter:blur(5px);backdrop-filter:blur(5px)}.catalog-dialog-panel,.catalog-actions-panel{position:relative;z-index:1;width:min(480px,100%);max-height:calc(100dvh - 32px);overflow:auto;padding:22px;border:1px solid var(--line);border-radius:22px;background:linear-gradient(155deg,#152138,#10033d);box-shadow:0 28px 80px rgba(0,0,0,.58)}.catalog-dialog-head{display:flex;align-items:flex-start;justify-content:space-between;gap:12px}.catalog-dialog-head b{font-size:18px}.catalog-dialog-head small{display:block;color:var(--tx2)}.catalog-dialog-x{width:38px;height:38px;border:1px solid var(--line);border-radius:11px;background:transparent;color:var(--tx);font-size:24px;cursor:pointer}.catalog-dialog-panel label{margin-top:12px}.catalog-save{width:100%;justify-content:center}.catalog-image-preview{display:flex;align-items:center;gap:12px;margin-top:16px;padding:10px;border-radius:14px;background:#091222;color:var(--tx2)}.catalog-image-preview img{width:80px;height:56px;object-fit:contain;border-radius:10px;background:#060c17}.catalog-favorite-note{margin-top:12px;padding:10px 12px;border-radius:11px;color:#fbbf24;background:rgba(245,158,11,.1);font-size:12px;font-weight:800}.catalog-actions{align-items:end}.catalog-actions-panel{width:min(430px,100%);display:grid;gap:8px;border-radius:24px 24px 18px 18px}.catalog-actions-panel>b{font-size:18px;text-align:center}.catalog-actions-panel>small{text-align:center;color:var(--tx2);margin-bottom:6px}.catalog-actions-grip{width:42px;height:4px;border-radius:99px;background:var(--tx3);margin:0 auto 6px}.catalog-actions-panel form{margin:0}.catalog-action-edit,.catalog-action-delete,.catalog-action-cancel{display:flex;align-items:center;justify-content:center;gap:9px;width:100%;min-height:48px;border:1px solid var(--line);border-radius:13px;color:var(--tx);background:rgba(255,255,255,.04);font:inherit;font-weight:800;cursor:pointer}.catalog-action-delete{color:#fca5a5;background:rgba(239,68,68,.1)}.catalog-action-cancel{color:var(--tx2);background:transparent}
.catalog-play-label>span{display:inline-block}.catalog-play-label>em{float:left;padding:2px 8px;border-radius:999px;color:var(--tx3);background:rgba(255,255,255,.05);font-size:10px;font-style:normal}.catalog-play-label>em.is-encrypted{color:var(--p);background:rgba(76, 14, 205,.12)}.catalog-crypto-tools{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:8px}.catalog-crypto-btn{display:inline-flex;align-items:center;justify-content:center;gap:7px;min-height:39px;padding:7px 14px;border:1px solid rgba(76, 14, 205,.32);border-radius:11px;color:var(--p);background:rgba(76, 14, 205,.1);font:inherit;font-size:12px;font-weight:900;cursor:pointer}.catalog-crypto-btn[hidden]{display:none}.catalog-crypto-btn.is-decrypt{color:var(--p2);border-color:rgba(124, 77, 255,.32);background:rgba(124, 77, 255,.1)}.catalog-crypto-btn:disabled{opacity:.55;cursor:wait}.catalog-crypto-tools small{flex-basis:100%;min-height:19px;color:var(--tx3)}.catalog-crypto-tools small.is-error{color:#fca5a5}.catalog-crypto-tools small.is-ok{color:var(--p)}
@media(max-width:620px){.catalog-toolbar{align-items:flex-start;flex-direction:column}.catalog-toolbar .btn{width:100%;justify-content:center}.catalog-admin-grid{grid-template-columns:1fr}.catalog-dialog{align-items:end;padding:10px}.catalog-dialog-panel{border-radius:24px 24px 16px 16px;padding:20px 16px calc(18px + env(safe-area-inset-bottom))}}
</style>
<script>
(function(){
  var cards=Array.prototype.slice.call(document.querySelectorAll('[data-catalog-card]'));
  var entry=document.getElementById('catalog-entry-dialog'),form=document.getElementById('catalog-entry-form'),actions=document.getElementById('catalog-actions');
  var current=null,timer=null,startX=0,startY=0,suppress=false;
  var addTitle=<?= json_encode((string)$catalogAddTitle, JSON_UNESCAPED_UNICODE) ?>,editTitle=<?= json_encode((string)$catalogEditTitle, JSON_UNESCAPED_UNICODE) ?>;
  function setHidden(el,hidden){if(!el)return;el.hidden=hidden;el.setAttribute('aria-hidden',hidden?'true':'false');document.body.style.overflow=hidden?'':'hidden'}
  function dataOf(card){try{return JSON.parse(card.getAttribute('data-edit')||'{}')}catch(e){return {}}}
  function openActions(card){current=card;suppress=true;card.classList.remove('is-holding');var id=actions.querySelector('[data-catalog-delete-id]');if(id)id.value=card.getAttribute('data-id')||'';setHidden(actions,false);setTimeout(function(){suppress=false},500)}
  function closeActions(){setHidden(actions,true)}
  function openEntry(data,title){closeActions();if(!entry||!form)return;form.reset();data=data||{};form.querySelectorAll('[data-field]').forEach(function(el){el.value=data[el.getAttribute('data-field')]??''});var ttl=document.getElementById('catalog-entry-title');if(ttl)ttl.textContent=title;var preview=form.querySelector('[data-catalog-preview]');if(preview)preview.src=data.image||data.logo||'/assets/img/channel.svg';form.dispatchEvent(new CustomEvent('catalog:entry-open',{detail:{data:data}}));setHidden(entry,false);setTimeout(function(){var f=form.querySelector('input[type=text]');if(f)f.focus()},60)}
  function closeEntry(){setHidden(entry,true)}
  document.querySelectorAll('[data-catalog-add]').forEach(function(btn){btn.addEventListener('click',function(){openEntry({},addTitle)})});
  cards.forEach(function(card){
    card.addEventListener('pointerdown',function(e){if(e.button!==undefined&&e.button!==0)return;startX=e.clientX;startY=e.clientY;card.classList.add('is-holding');timer=setTimeout(function(){openActions(card)},560)});
    ['pointerup','pointercancel','pointerleave'].forEach(function(ev){card.addEventListener(ev,function(){clearTimeout(timer);card.classList.remove('is-holding')})});
    card.addEventListener('pointermove',function(e){if(Math.abs(e.clientX-startX)>10||Math.abs(e.clientY-startY)>10){clearTimeout(timer);card.classList.remove('is-holding')}});
    card.addEventListener('contextmenu',function(e){e.preventDefault();clearTimeout(timer);openActions(card)});
    card.addEventListener('click',function(e){if(suppress)e.preventDefault()});
  });
  var edit=actions&&actions.querySelector('[data-catalog-edit]');if(edit)edit.addEventListener('click',function(){if(current)openEntry(dataOf(current),editTitle)});
  document.querySelectorAll('[data-catalog-close]').forEach(function(btn){btn.addEventListener('click',closeEntry)});
  document.querySelectorAll('[data-catalog-actions-close]').forEach(function(btn){btn.addEventListener('click',closeActions)});
  var imageInput=form&&form.querySelector('[data-image-input]');if(imageInput)imageInput.addEventListener('change',function(){var file=imageInput.files&&imageInput.files[0],preview=form.querySelector('[data-catalog-preview]');if(file&&preview)preview.src=URL.createObjectURL(file)});
  document.addEventListener('keydown',function(e){if(e.key==='Escape'){closeActions();closeEntry()}});
})();
</script>
